    // Since time can be large, we need to find a way to limit it. However, for the problem, it's not clear the upper bound.
    // So we proceed with Dijkstra's algorithm where each state is (i, j, time)
    // But to optimize, we can note that for any cell (i,j), the minimal cost up to that cell can be achieved with minimal time steps.
    // So we can track the minimal cost for each cell (i,j) and the time parity (odd or even)
    // Because the action depends on the time's parity (odd or even)

    // dist[i][j][0] represents minimal cost to reach (i,j) at even time
    // dist[i][j][1] represents minimal cost to reach (i,j) at odd time
    long[][][] dist = new long[(int)m][(int)n][2];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            dist[i][j][0] = Long.MAX_VALUE;
            dist[i][j][1] = Long.MAX_VALUE;
        }
    }

    // Starting at (0,0) at time 1 (odd)
    long enterCost = (0 + 1) * (0 + 1);
    dist[0][0][1] = enterCost;
    pq.offer(new long[]{0, 0, 1, enterCost});

    while (!pq.isEmpty()) {
        long[] curr = pq.poll();
        int i = (int)curr[0];
        int j = (int)curr[1];
        long time = curr[2];
        long cost = curr[3];

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (cost > dist[i][j][(int)(time % 2)]) {
            continue;
        }

        if (time % 2 == 1) {
            // Odd time: move right or down
            for (int[] dir : dirs) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni < m && nj < n) {
                    long newTime = time + 1;
                    long newEnterCost = (ni + 1) * (nj + 1);
                    long newCost = cost + newEnterCost;
                    if (newCost < dist[ni][nj][(int)(newTime % 2)]) {
                        dist[ni][nj][(int)(newTime % 2)] = newCost;
                        pq.offer(new long[]{ni, nj, newTime, newCost});
                    }
                }
            }
        } else {
            // Even time: wait
            long newTime = time + 1;
            long waitCostHere = waitCost[i][j];
            long newCost = cost + waitCostHere;
            if (newCost < dist[i][j][(int)(newTime % 2)]) {
                dist[i][j][(int)(newTime % 2)] = newCost;
                pq.offer(new long[]{i, j, newTime, newCost});
            }
        }
    }

    return -1; // should not reach here if m and n are positive
}
